"""
IoT Service Architecture - Step 5 of IoT Design Methodology
Demonstrates Service-Oriented Architecture (SOA) for IoT systems
"""
from abc import ABC, abstractmethod
from datetime import datetime
from typing import Dict, List, Any
import json
import uuid

# ============================================
# SERVICE INTERFACES (Abstract Base Classes)
# ============================================

class IoTService(ABC):
    """Base class for all IoT services"""

    @abstractmethod
    def process(self, data: Any) -> Any:
        pass

class DeviceService(IoTService):
    """
    Device Service - Manages device connectivity, provisioning, and firmware
    Step 5: Service Specification
    """

    def __init__(self):
        self.devices: Dict[str, dict] = {}

    def register_device(self, device_id: str, device_type: str, metadata: dict) -> dict:
        """Device provisioning and registration"""
        self.devices[device_id] = {
            "device_id": device_id,
            "device_type": device_type,
            "metadata": metadata,
            "status": "active",
            "registered_at": datetime.utcnow().isoformat()
        }
        return self.devices[device_id]

    def process(self, data: Any) -> Any:
        # Process device-related operations
        return {"status": "processed", "service": "DeviceService"}

    def get_device(self, device_id: str) -> dict:
        return self.devices.get(device_id, {})

class DataIngestionService(IoTService):
    """
    Data Ingestion Service - Accepts and validates data streams from devices
    """

    def __init__(self):
        self.data_stream: List[dict] = []

    def ingest(self, device_id: str, payload: dict) -> dict:
        """Validate and store incoming sensor data"""
        validated_data = {
            "id": str(uuid.uuid4()),
            "device_id": device_id,
            "payload": payload,
            "received_at": datetime.utcnow().isoformat(),
            "validated": True
        }
        self.data_stream.append(validated_data)
        return validated_data

    def process(self, data: Any) -> Any:
        return self.ingest(data.get("device_id"), data.get("payload", {}))

class StorageService(IoTService):
    """
    Storage Service - Persists data into time-series databases
    """

    def __init__(self):
        self.time_series_db: Dict[str, List[dict]] = {}
        self.document_db: List[dict] = []

    def store_time_series(self, sensor_id: str, timestamp: str, value: float) -> bool:
        """Store sensor reading in time-series format"""
        if sensor_id not in self.time_series_db:
            self.time_series_db[sensor_id] = []
        self.time_series_db[sensor_id].append({
            "timestamp": timestamp,
            "value": value
        })
        return True

    def store_document(self, document: dict) -> bool:
        """Store document-style data"""
        self.document_db.append(document)
        return True

    def process(self, data: Any) -> Any:
        return {"status": "stored", "service": "StorageService"}

class AnalyticsService(IoTService):
    """
    Analytics Service - Processes data to generate insights, alerts, predictions
    """

    def __init__(self):
        self.thresholds = {"temperature": 30.0, "humidity": 80.0}
        self.alerts: List[dict] = []

    def analyze(self, data: dict) -> dict:
        """Analyze sensor data and generate alerts"""
        alerts = []
        payload = data.get("payload", {})

        if "temperature" in payload:
            if payload["temperature"] > self.thresholds["temperature"]:
                alerts.append({
                    "type": "HIGH_TEMPERATURE",
                    "value": payload["temperature"],
                    "threshold": self.thresholds["temperature"]
                })

        return {"alerts": alerts, "insights": []}

    def process(self, data: Any) -> Any:
        return self.analyze(data)

class APIService(IoTService):
    """
    API Service - Provides REST interface for applications and users
    """

    def __init__(self, storage_service: StorageService):
        self.storage = storage_service

    def get_latest_readings(self, sensor_id: str, limit: int = 10) -> List[dict]:
        """Query API for recent sensor readings"""
        readings = self.storage.time_series_db.get(sensor_id, [])
        return readings[-limit:]

    def process(self, data: Any) -> Any:
        return {"status": "api_response", "service": "APIService"}

# ============================================
# IOT SYSTEM ORCHESTRATION
# ============================================

class IoTSystem:
    """
    Main IoT System that orchestrates all services
    Demonstrates Microservices Architecture for IoT
    """

    def __init__(self):
        # Initialize all services (Step 5: Service Specification)
        self.device_service = DeviceService()
        self.ingestion_service = DataIngestionService()
        self.storage_service = StorageService()
        self.analytics_service = AnalyticsService()
        self.api_service = APIService(self.storage_service)

    def register_and_ingest(self, device_id: str, sensor_data: dict):
        """Process incoming IoT data through the service pipeline"""

        # Step 1: Device Management
        device = self.device_service.register_device(
            device_id, "temperature_sensor", {"location": "warehouse_a"}
        )

        # Step 2: Data Ingestion
        ingested = self.ingestion_service.ingest(device_id, sensor_data)

        # Step 3: Storage
        if "temperature" in sensor_data:
            self.storage_service.store_time_series(
                device_id,
                ingested["received_at"],
                sensor_data["temperature"]
            )

        # Step 4: Analytics
        analysis = self.analytics_service.analyze(ingested)

        return {
            "device": device,
            "data": ingested,
            "analysis": analysis
        }

# ============================================
# DEMONSTRATION
# ============================================

def demonstrate_service_architecture():
    print("=" * 60)
    print("IoT Service Architecture Demonstration (Step 5)")
    print("=" * 60)

    # Create IoT system with all services
    iot_system = IoTSystem()

    # Simulate incoming sensor data
    sensor_reading = {
        "temperature": 32.5,
        "humidity": 65.0
    }

    # Process through service pipeline
    result = iot_system.register_and_ingest("SENSOR-001", sensor_reading)

    print("\nProcessed Result:")
    print(json.dumps(result, indent=2))

    # Query via API service
    print("\nAPI Query - Latest Readings:")
    readings = iot_system.api_service.get_latest_readings("SENSOR-001")
    print(json.dumps(readings, indent=2))

if __name__ == "__main__":
    demonstrate_service_architecture()

/*
 * IoT Data Flow Simulation - Step 2 & 6 of IoT Design Methodology
 * Demonstrates Process Specification using Data Flow Diagrams
 * and IoT Level classification (Level 3: Multiple devices with cloud)
 */

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <stdbool.h>

// ============================================
// DATA STRUCTURES FOR IOT ENTITIES
// ============================================

#define MAX_DEVICES 10
#define MAX_NAME_LEN 32

// Sensor data structure
typedef struct {
    char sensor_id[MAX_NAME_LEN];
    float temperature;
    float humidity;
    char timestamp[32];
    bool is_valid;
} SensorData;

// Device entity (from Domain Model - Step 3)
typedef struct {
    char device_id[MAX_NAME_LEN];
    char device_type[MAX_NAME_LEN];
    float battery_level;
    bool online_status;
} IoTDevice;

// Processed data for cloud transmission
typedef struct {
    char device_id[MAX_NAME_LEN];
    float processed_value;
    char processed_timestamp[32];
    char alert_type[32];
} CloudMessage;

// ============================================
// IOT LEVEL 3 ARCHITECTURE COMPONENTS
// ============================================

/*
 * IoT Level 3: Multiple devices, cloud storage and analysis
 * 
 * [Sensor] --> [Microcontroller] --> [Gateway] --> [Cloud Service] --> [Database]
 *                                  (Edge/Fog)      (Analytics)         (Storage)
 */

// Simulated Sensor (Hardware Layer)
void read_sensor(SensorData *data, const char *sensor_id) {
    strncpy(data->sensor_id, sensor_id, MAX_NAME_LEN - 1);
    // Simulate reading from hardware sensor
    data->temperature = 20.0 + (rand() % 150) / 10.0;  // 20-35°C
    data->humidity = 40.0 + (rand() % 400) / 10.0;     // 40-80%
    strcpy(data->timestamp, "2024-01-15T10:30:00Z");
    data->is_valid = true;

    printf("[SENSOR] ID: %s, Temp: %.1f°C, Humidity: %.1f%%\n", 
           sensor_id, data->temperature, data->humidity);
}

// Microcontroller Processing (Edge Node)
void process_at_edge(SensorData *raw, CloudMessage *processed) {
    strncpy(processed->device_id, raw->sensor_id, MAX_NAME_LEN - 1);

    // Simple data processing: average temperature
    processed->processed_value = raw->temperature;
    strcpy(processed->processed_timestamp, raw->timestamp);

    // Edge-level threshold check
    if (raw->temperature > 30.0) {
        strcpy(processed->alert_type, "HIGH_TEMP_ALERT");
    } else if (raw->temperature < 15.0) {
        strcpy(processed->alert_type, "LOW_TEMP_ALERT");
    } else {
        strcpy(processed->alert_type, "NORMAL");
    }

    printf("[EDGE] Processed: %.1f°C, Alert: %s\n", 
           processed->processed_value, processed->alert_type);
}

// Cloud Service Processing (Analytics)
void process_at_cloud(CloudMessage *msg, char *analytics_result) {
    // Cloud-level advanced analytics
    if (strcmp(msg->alert_type, "HIGH_TEMP_ALERT") == 0) {
        sprintf(analytics_result, 
                "Action: Send notification to HVAC system. "
                "Location: %s. Severity: Medium.", 
                msg->device_id);
    } else {
        sprintf(analytics_result, 
                "Action: Log data for historical analysis. "
                "Location: %s. Status: Normal operations.", 
                msg->device_id);
    }

    printf("[CLOUD] Analytics: %s\n", analytics_result);
}

// Database Storage
void store_in_database(CloudMessage *msg, const char *analytics) {
    printf("[DATABASE] Storing: Device=%s, Value=%.1f, Alert=%s\n",
           msg->device_id, msg->processed_value, msg->alert_type);
    printf("[DATABASE] Analytics: %s\n", analytics);
}

// ============================================
// DATA FLOW DIAGRAM IMPLEMENTATION
// ============================================

/*
 * Complete Data Flow (Process Specification - Step 2):
 * 
 *   +---------+     +----------+     +---------+     +----------+     +---------+
 *   | Sensor  |---->|   Edge   |---->|  Cloud  |---->|Analytics |---->|   DB    |
 *   | (Data)  |     | (Process)|     | (Ingest)|     | (Analyze)|     | (Store) |
 *   +---------+     +----------+     +---------+     +----------+     +---------+
 */

void execute_data_flow(const char *sensor_id) {
    printf("\n=== Executing IoT Data Flow (Level 3) ===\n");

    // DFD Level 0: External Entity - Sensor
    SensorData raw_data;
    read_sensor(&raw_data, sensor_id);

    // DFD Process 1: Edge Processing
    CloudMessage processed_msg;
    process_at_edge(&raw_data, &processed_msg);

    // DFD Process 2: Cloud Ingestion
    printf("[CLOUD] Receiving data from edge gateway...\n");

    // DFD Process 3: Analytics
    char analytics_result[256];
    process_at_cloud(&processed_msg, analytics_result);

    // DFD Data Store: Database
    store_in_database(&processed_msg, analytics_result);

    printf("=== Data Flow Complete ===\n\n");
}

// ============================================
// MAIN DEMONSTRATION
// ============================================

int main() {
    printf("==============================================\n");
    printf("IoT Data Flow Simulation\n");
    printf("Steps 2 & 6: Process Specification + IoT Levels\n");
    printf("==============================================\n");

    // Simulate multiple sensors (Level 3: Multiple devices)
    const char *sensors[] = {"TEMP-001", "TEMP-002", "TEMP-003"};
    int num_sensors = 3;

    for (int i = 0; i < num_sensors; i++) {
        execute_data_flow(sensors[i]);
    }

    printf("\n--- IoT Level Classification ---\n");
    printf("This system represents: Level 3\n");
    printf("- Multiple devices: %d sensors\n", num_sensors);
    printf("- Cloud storage: Yes\n");
    printf("- Edge processing: Basic threshold checking\n");
    printf("- Analytics: Cloud-based pattern analysis\n");

    return 0;
}
